/**
 * ReferencesModal 组件
 * 显示引用详情的模态框
 */
import React from 'react';
import { memo, useCallback, useMemo } from 'react';
import { Modal, Tabs } from 'antd';
import { getActions } from '../../../global';

import type { MessageReference, WebReference } from '../messages/types';

import buildClassName from '../../../util/buildClassName';

import MessageReferenceCard from './MessageReferenceCard';
import WebReferenceCard from './WebReferenceCard';

import styles from './ReferencesModal.module.scss';

interface OwnProps {
  isOpen: boolean;
  messageReferences: MessageReference[];
  webpageReferences: WebReference[];
  onClose: () => void;
  onOpenWebpage?: (url: string) => void;
  className?: string;
}

const ReferencesModal = ({
  isOpen,
  messageReferences,
  webpageReferences,
  onClose,
  onOpenWebpage,
  className,
}: OwnProps) => {
  const hasMessages = messageReferences.length > 0;
  const hasWebpages = webpageReferences.length > 0;
  const { focusMessage } = getActions();

  const handleNavigateToMessage = useCallback((messageId: string, chatId: string) => {
    focusMessage({
      chatId, messageId: Number(messageId),
    });
    onClose();
  }, [onClose]);

  // 构建 Tabs 配置
  const tabItems = useMemo(() => {
    const items = [];

    if (hasMessages) {
      items.push({
        key: 'messages',
        label: `Original Messages (${messageReferences.length})`,
        children: (
          <div className={styles.list}>
            {messageReferences.map((ref) => (
              <MessageReferenceCard
                key={ref.messageId}
                reference={ref}
                onNavigate={handleNavigateToMessage}
              />
            ))}
          </div>
        ),
      });
    }

    if (hasWebpages) {
      items.push({
        key: 'webpages',
        label: `Webpages (${webpageReferences.length})`,
        children: (
          <div className={styles.list}>
            {webpageReferences.map((ref, index) => (
              <WebReferenceCard

                key={`${ref.url}-${index}`}
                reference={ref}
              />
            ))}
          </div>
        ),
      });
    }

    return items;
  }, [hasMessages, hasWebpages, messageReferences, webpageReferences, handleNavigateToMessage]);

  return (
    <Modal
      open={isOpen}
      onCancel={onClose}
      className={buildClassName(styles.modal, className)}
      title="Reference source"
      footer={undefined}
      width={600}
    >
      <div className={styles.content}>
        {tabItems.length > 0 ? (
          <Tabs
            items={tabItems}
            defaultActiveKey={tabItems[0]?.key}
            className={styles.tabs}
          />
        ) : (
          <div className={styles.empty}>
            暂无引用来源
          </div>
        )}
      </div>
    </Modal>
  );
};

export default memo(ReferencesModal);
